public static class StatHelper
{
    static StatHelper()
    {
        Console.WriteLine("StatHelper chargée - prête pour les calculs.");
    }

    public static double CalculerMoyenne(double[] valeurs)
    {
        if (valeurs == null || valeurs.Length == 0)
            throw new ArgumentException("Le tableau ne peut pas être vide.");
        double somme = 0;
        foreach (var v in valeurs) somme += v;
        return somme / valeurs.Length;
    }

    public static double CalculerEcartType(double[] valeurs)
    {
        double moyenne = CalculerMoyenne(valeurs);
        double sommeCarres = 0;
        foreach (var v in valeurs)
        {
            sommeCarres += Math.Pow(v - moyenne, 2);
        }
        return Math.Sqrt(sommeCarres / valeurs.Length);
    }
}
```

